"use client";

import { memo, useCallback, useEffect, useId, useMemo, useState } from "react";
import { TooltipProvider } from "@/components/ui/tooltip";
import { cn } from "@/lib/utils";
import { BillingToggle } from "./parts/billing-toggle";
import { ComparisonTable } from "./parts/comparison-table";
import { TierCard } from "./parts/tier-card";
import { resolveTone } from "./parts/tone";
import {
  DEFAULT_LABELS,
  type BillingPeriod,
  type PricingTable01Props,
} from "./types";

/**
 * PricingTable01 — side-by-side pricing tiers with optional monthly/annual toggle,
 * highlighted-tier badge, per-feature included rows, and a comparison-table layout.
 *
 * Billing-period state is controlled-or-uncontrolled (mirrors React input convention).
 * CTAs accept ReactNode (load-bearing, consumer wraps with router primitive) OR a
 * CtaSpec convenience overload that renders a plain anchor/button.
 */
function PricingTable01Impl(props: PricingTable01Props) {
  const {
    heading,
    subheading,
    headingAs = "h2",
    tiers,
    layout = "cards",
    billingToggle = "none",
    billing: controlledBilling,
    defaultBilling = "monthly",
    onBillingChange,
    tone = "primary",
    onTierCtaClick,
    labels: labelsProp,
    className,
    tierCardClassName,
    highlightedRingClassName,
    id: idProp,
  } = props;

  const HeadingTag = headingAs;
  const generatedId = useId();
  const rootId = idProp ?? generatedId;
  const headingId = `${rootId}-heading`;

  const labels = useMemo(
    () => ({ ...DEFAULT_LABELS, ...labelsProp }),
    [labelsProp],
  );
  const toneClasses = useMemo(() => resolveTone(tone), [tone]);

  const [internalBilling, setInternalBilling] =
    useState<BillingPeriod>(defaultBilling);
  const isControlled = controlledBilling !== undefined;
  const billing = isControlled ? controlledBilling : internalBilling;

  const handleBillingChange = useCallback(
    (period: BillingPeriod) => {
      if (!isControlled) setInternalBilling(period);
      onBillingChange?.(period);
    },
    [isControlled, onBillingChange],
  );

  const handleTierCtaClick = useCallback(
    (tierName: string) => {
      onTierCtaClick?.(tierName);
    },
    [onTierCtaClick],
  );

  useEffect(() => {
    if (process.env.NODE_ENV === "production") return;
    if (tiers.length < 2 || tiers.length > 4) {
      console.warn(
        `[pricing-table-01] expected 2–4 tiers, received ${tiers.length}. Layout assumes 2–4 tiers.`,
      );
    }
    const highlightedCount = tiers.filter((tier) => tier.highlighted).length;
    if (highlightedCount > 1) {
      console.warn(
        `[pricing-table-01] ${highlightedCount} tiers marked highlighted; only one tier per table is the intended pattern.`,
      );
    }
  }, [tiers]);

  const showToggle = billingToggle === "monthly-annual";

  // F-cross-13: dropped `delayDuration={150}` from <TooltipProvider> below —
  // Radix-vs-Base-UI prop-name divergence (`delayDuration` vs `delay`). Per
  // the locked defensive pattern, syntactically-divergent props are dropped
  // at the producer side so consumer-side shadcn-add installs (which ship
  // Base UI) don't carry a stale prop name. Default delay (~700ms Radix /
  // ~600ms Base UI) is acceptable for a pricing-table tooltip surface.
  return (
    <TooltipProvider>
      <section
        id={rootId}
        aria-labelledby={heading ? headingId : undefined}
        className={cn("flex flex-col gap-8", className)}
      >
        {(heading || subheading || showToggle) && (
          <header className="flex flex-col items-center gap-4 text-center">
            {heading ? (
              <HeadingTag
                id={headingId}
                className="text-2xl font-semibold text-foreground sm:text-3xl"
              >
                {heading}
              </HeadingTag>
            ) : null}
            {subheading ? (
              <p className="max-w-2xl text-sm text-muted-foreground">
                {subheading}
              </p>
            ) : null}
            {showToggle ? (
              <BillingToggle
                billing={billing}
                onChange={handleBillingChange}
                labels={labels}
                toneClasses={toneClasses}
              />
            ) : null}
          </header>
        )}

        {layout === "table" ? (
          <ComparisonTable
            tiers={tiers}
            billing={billing}
            labels={labels}
            toneClasses={toneClasses}
            onTierCtaClick={handleTierCtaClick}
            highlightedRingClassName={highlightedRingClassName}
          />
        ) : (
          <div
            className={cn(
              "grid gap-6",
              "grid-cols-1",
              tiers.length === 2 && "md:grid-cols-2",
              tiers.length === 3 && "md:grid-cols-2 lg:grid-cols-3",
              tiers.length >= 4 && "md:grid-cols-2 lg:grid-cols-4",
            )}
          >
            {tiers.map((tier) => (
              <TierCard
                key={tier.name}
                tier={tier}
                billing={billing}
                labels={labels}
                toneClasses={toneClasses}
                onTierCtaClick={handleTierCtaClick}
                className={tierCardClassName}
                highlightedRingClassName={highlightedRingClassName}
              />
            ))}
          </div>
        )}
      </section>
    </TooltipProvider>
  );
}

export const PricingTable01 = memo(PricingTable01Impl);
PricingTable01.displayName = "PricingTable01";

export default PricingTable01;

export { PricingTable01, default } from "./pricing-table-01";
export type {
  BillingPeriod,
  CtaSpec,
  CtaVariant,
  CurrencyDisplay,
  PricingBillingToggle,
  PricingFeature,
  PricingHeadingLevel,
  PricingLayout,
  PricingTable01Props,
  PricingTableLabels,
  PricingTier,
  PricingTone,
} from "./types";
export { meta } from "./meta";

import type { ReactNode } from "react";

export type PricingLayout = "cards" | "table";

export type PricingBillingToggle = "none" | "monthly-annual";

export type BillingPeriod = "monthly" | "annual";

export type PricingTone = "primary" | "accent" | "muted";

export type CurrencyDisplay = "symbol" | "code";

export type PricingHeadingLevel = "h2" | "h3" | "h4";

export type CtaVariant = "primary" | "outline";

export interface CtaSpec {
  label: string;
  href?: string;
  onClick?: () => void;
  variant?: CtaVariant;
  ariaLabel?: string;
}

export interface PricingFeature {
  label: string;
  included: boolean;
  tooltip?: string;
}

export interface PricingTier {
  name: string;
  description?: string;
  /** Per-month price. Always required (annual mode shows the monthly equivalent). */
  priceMonthly: number;
  /** Per-month rate when billed annually. The optional yearly hint is derived as priceAnnual * 12. */
  priceAnnual?: number;
  /** ISO 4217 (e.g. "USD", "EUR", "TRY"). */
  currencyCode: string;
  /** Default: "symbol". */
  currencyDisplay?: CurrencyDisplay;
  /** Overrides default periodLabel from the labels bag (e.g. "per user / month"). */
  periodLabel?: string;
  features: ReadonlyArray<PricingFeature>;
  /** Load-bearing: ReactNode. Pass a CtaSpec for the convenience case. */
  cta: ReactNode | CtaSpec;
  highlighted?: boolean;
  /** Per-tier override of the "Most popular" badge text. */
  badge?: string;
}

export interface PricingTableLabels {
  monthlyLabel?: string;
  annualLabel?: string;
  /** sr-only label for the toggle radiogroup. */
  toggleGroupLabel?: string;
  popularBadge?: string;
  periodMonthly?: string;
  periodAnnual?: string;
  /** Opt-in: rendered when priceMonthly === 0 (instead of the formatted "0"). */
  freeLabel?: string;
  /**
   * Small label next to the annual price. String form supports the "{amount}"
   * placeholder; function form receives the formatted yearly total.
   * Pass `null` to hide.
   */
  yearlyHint?: string | ((yearlyTotal: string) => string) | null;
  /** sr-only state label for "included" features. */
  featureIncluded?: string;
  /** sr-only state label for "not included" features. */
  featureExcluded?: string;
}

export interface ResolvedLabels {
  monthlyLabel: string;
  annualLabel: string;
  toggleGroupLabel: string;
  popularBadge: string;
  periodMonthly: string;
  periodAnnual: string;
  freeLabel: string | undefined;
  yearlyHint: string | ((yearlyTotal: string) => string) | null;
  featureIncluded: string;
  featureExcluded: string;
}

export const DEFAULT_LABELS: ResolvedLabels = {
  monthlyLabel: "Monthly",
  annualLabel: "Annual",
  toggleGroupLabel: "Billing period",
  popularBadge: "Most popular",
  periodMonthly: "per month",
  periodAnnual: "per month, billed annually",
  freeLabel: undefined,
  yearlyHint: "{amount} / yr",
  featureIncluded: "Included",
  featureExcluded: "Not included",
};

export interface PricingTable01Props {
  heading?: string;
  subheading?: string;
  headingAs?: PricingHeadingLevel;

  /** 2–4 tiers. Out-of-range length logs a dev-mode warn but still renders. */
  tiers: ReadonlyArray<PricingTier>;

  /** Layout variant. Default: "cards". */
  layout?: PricingLayout;

  /** Billing toggle mode. Default: "none". */
  billingToggle?: PricingBillingToggle;

  /** Controlled billing period. */
  billing?: BillingPeriod;
  /** Uncontrolled initial value. Default: "monthly". */
  defaultBilling?: BillingPeriod;
  onBillingChange?: (period: BillingPeriod) => void;

  /** Color tone. Default: "primary". */
  tone?: PricingTone;

  /** Fires for CtaSpec tiers after the consumer's onClick. ReactNode CTAs wire their own. */
  onTierCtaClick?: (tierName: string) => void;

  labels?: PricingTableLabels;

  className?: string;
  /** Class on each tier card / column. */
  tierCardClassName?: string;
  /** Class on the highlighted-tier ring/border. */
  highlightedRingClassName?: string;

  /** Override the root id (drives aria-labelledby wiring). Default: useId(). */
  id?: string;
}

export interface ResolvedTone {
  cardBorder: string;
  highlightRing: string;
  highlightBorder: string;
  badgeBg: string;
  badgeText: string;
  toggleActiveBg: string;
  toggleActiveText: string;
}

import { useRef } from "react";
import type { KeyboardEvent } from "react";
import { cn } from "@/lib/utils";
import type { BillingPeriod, ResolvedLabels, ResolvedTone } from "../types";

interface BillingToggleProps {
  billing: BillingPeriod;
  onChange: (period: BillingPeriod) => void;
  labels: ResolvedLabels;
  toneClasses: ResolvedTone;
  className?: string;
}

const SEGMENTS: ReadonlyArray<BillingPeriod> = ["monthly", "annual"];

export function BillingToggle({
  billing,
  onChange,
  labels,
  toneClasses,
  className,
}: BillingToggleProps) {
  const refs = useRef<Array<HTMLButtonElement | null>>([null, null]);

  const focusSegment = (index: number) => {
    const next = (index + SEGMENTS.length) % SEGMENTS.length;
    const period = SEGMENTS[next];
    refs.current[next]?.focus();
    onChange(period);
  };

  const handleKeyDown = (
    event: KeyboardEvent<HTMLButtonElement>,
    index: number,
  ) => {
    if (event.key === "ArrowRight" || event.key === "ArrowDown") {
      event.preventDefault();
      focusSegment(index + 1);
    } else if (event.key === "ArrowLeft" || event.key === "ArrowUp") {
      event.preventDefault();
      focusSegment(index - 1);
    } else if (event.key === "Home") {
      event.preventDefault();
      focusSegment(0);
    } else if (event.key === "End") {
      event.preventDefault();
      focusSegment(SEGMENTS.length - 1);
    }
  };

  return (
    <div
      role="radiogroup"
      aria-label={labels.toggleGroupLabel}
      className={cn(
        "inline-flex items-center rounded-full border border-border bg-muted/40 p-1 text-sm",
        className,
      )}
    >
      {SEGMENTS.map((period, index) => {
        const active = billing === period;
        const segmentLabel =
          period === "monthly" ? labels.monthlyLabel : labels.annualLabel;
        return (
          <button
            key={period}
            ref={(node) => {
              refs.current[index] = node;
            }}
            type="button"
            role="radio"
            aria-checked={active}
            tabIndex={active ? 0 : -1}
            onClick={() => onChange(period)}
            onKeyDown={(event) => handleKeyDown(event, index)}
            className={cn(
              "rounded-full px-4 py-1.5 font-medium transition-colors",
              "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring",
              active
                ? cn(toneClasses.toggleActiveBg, toneClasses.toggleActiveText)
                : "text-muted-foreground hover:text-foreground",
            )}
          >
            {segmentLabel}
          </button>
        );
      })}
    </div>
  );
}

import { Check, X } from "lucide-react";
import {
  Tooltip,
  TooltipContent,
  TooltipTrigger,
} from "@/components/ui/tooltip";
import { cn } from "@/lib/utils";
import { PriceDisplay } from "./price-display";
import { TierCta } from "./tier-cta";
import type {
  BillingPeriod,
  PricingFeature,
  PricingTier,
  ResolvedLabels,
  ResolvedTone,
} from "../types";

interface ComparisonTableProps {
  tiers: ReadonlyArray<PricingTier>;
  billing: BillingPeriod;
  labels: ResolvedLabels;
  toneClasses: ResolvedTone;
  onTierCtaClick: (tierName: string) => void;
  className?: string;
  highlightedRingClassName?: string;
}

interface FeatureRow {
  label: string;
  tooltip: string | undefined;
  perTier: Array<PricingFeature | undefined>;
}

function buildFeatureRows(
  tiers: ReadonlyArray<PricingTier>,
): ReadonlyArray<FeatureRow> {
  const seen = new Map<string, FeatureRow>();
  for (let tierIndex = 0; tierIndex < tiers.length; tierIndex++) {
    const tier = tiers[tierIndex];
    for (const feature of tier.features) {
      const existing = seen.get(feature.label);
      if (existing) {
        existing.perTier[tierIndex] = feature;
        if (!existing.tooltip && feature.tooltip) {
          existing.tooltip = feature.tooltip;
        }
      } else {
        const perTier: Array<PricingFeature | undefined> = new Array(
          tiers.length,
        ).fill(undefined);
        perTier[tierIndex] = feature;
        seen.set(feature.label, {
          label: feature.label,
          tooltip: feature.tooltip,
          perTier,
        });
      }
    }
  }
  return Array.from(seen.values());
}

export function ComparisonTable({
  tiers,
  billing,
  labels,
  toneClasses,
  onTierCtaClick,
  className,
  highlightedRingClassName,
}: ComparisonTableProps) {
  const rows = buildFeatureRows(tiers);

  return (
    <div className={cn("w-full overflow-x-auto", className)}>
      <table className="w-full min-w-[640px] border-collapse text-sm">
        <thead>
          <tr>
            <th scope="col" className="w-1/4 p-3 text-start font-normal" />
            {tiers.map((tier) => {
              const isHighlighted = !!tier.highlighted;
              const badgeText = tier.badge ?? labels.popularBadge;
              return (
                <th
                  key={tier.name}
                  scope="col"
                  className={cn(
                    "p-3 text-start align-top",
                    isHighlighted
                      ? cn(
                          "rounded-t-xl ring-2 ring-inset",
                          toneClasses.highlightRing,
                          highlightedRingClassName,
                        )
                      : null,
                  )}
                >
                  <div className="flex flex-col gap-1.5">
                    {isHighlighted ? (
                      <span
                        className={cn(
                          "inline-flex w-fit items-center rounded-full px-2 py-0.5 text-[10px] font-semibold uppercase tracking-wide",
                          toneClasses.badgeBg,
                          toneClasses.badgeText,
                        )}
                      >
                        {badgeText}
                      </span>
                    ) : null}
                    <span className="text-base font-semibold text-foreground">
                      {tier.name}
                    </span>
                    {tier.description ? (
                      <span className="text-xs text-muted-foreground">
                        {tier.description}
                      </span>
                    ) : null}
                  </div>
                </th>
              );
            })}
          </tr>
        </thead>
        <tbody>
          <tr className="border-t border-border/60">
            <th scope="row" className="sticky start-0 bg-card p-3 text-start text-xs font-medium text-muted-foreground">
              {billing === "annual" ? labels.annualLabel : labels.monthlyLabel}
            </th>
            {tiers.map((tier) => (
              <td key={tier.name} className="p-3 align-top">
                <PriceDisplay tier={tier} billing={billing} labels={labels} />
              </td>
            ))}
          </tr>
          <tr className="border-t border-border/60">
            <th
              scope="row"
              className="sticky start-0 bg-card p-3 text-start text-xs font-medium text-muted-foreground"
            >
              <span className="sr-only">Call to action</span>
            </th>
            {tiers.map((tier) => (
              <td key={tier.name} className="p-3 align-top">
                <TierCta
                  cta={tier.cta}
                  tierName={tier.name}
                  onTierCtaClick={onTierCtaClick}
                />
              </td>
            ))}
          </tr>
          {rows.map((row) => (
            <tr key={row.label} className="border-t border-border/60">
              <th
                scope="row"
                className="sticky start-0 bg-card p-3 text-start text-sm font-normal text-foreground"
              >
                {row.tooltip ? (
                  <Tooltip>
                    <TooltipTrigger asChild>
                      <span className="cursor-help underline decoration-dotted decoration-muted-foreground/40 underline-offset-2">
                        {row.label}
                      </span>
                    </TooltipTrigger>
                    <TooltipContent>{row.tooltip}</TooltipContent>
                  </Tooltip>
                ) : (
                  row.label
                )}
              </th>
              {row.perTier.map((cell, index) => {
                const tier = tiers[index];
                const included = cell?.included ?? false;
                const stateLabel = included
                  ? labels.featureIncluded
                  : labels.featureExcluded;
                const Icon = included ? Check : X;
                return (
                  <td
                    key={tier.name}
                    className="p-3 align-top text-muted-foreground"
                  >
                    <span className="sr-only">{stateLabel}</span>
                    <Icon
                      aria-hidden="true"
                      className={cn(
                        "h-4 w-4",
                        included ? "text-primary" : "text-muted-foreground",
                      )}
                    />
                  </td>
                );
              })}
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

import { cn } from "@/lib/utils";
import type { BillingPeriod, PricingTier, ResolvedLabels } from "../types";
import { formatPrice, formatYearly, resolveYearlyHint } from "./format";

interface PriceDisplayProps {
  tier: PricingTier;
  billing: BillingPeriod;
  labels: ResolvedLabels;
  className?: string;
}

export function PriceDisplay({
  tier,
  billing,
  labels,
  className,
}: PriceDisplayProps) {
  const {
    priceMonthly,
    priceAnnual,
    currencyCode,
    currencyDisplay = "symbol",
    periodLabel,
  } = tier;

  const showAnnual = billing === "annual" && priceAnnual !== undefined;
  const activePrice = showAnnual ? (priceAnnual as number) : priceMonthly;

  const isFree =
    activePrice === 0 && labels.freeLabel !== undefined && billing === "monthly";

  const formattedActive = formatPrice(activePrice, currencyCode, currencyDisplay);
  const formattedMonthly = formatPrice(priceMonthly, currencyCode, currencyDisplay);

  const periodCopy =
    periodLabel ??
    (billing === "annual" ? labels.periodAnnual : labels.periodMonthly);

  const showStrikethrough =
    showAnnual && (priceAnnual as number) < priceMonthly;

  const yearlyHintText = showAnnual
    ? resolveYearlyHint(
        labels.yearlyHint,
        formatYearly(priceAnnual as number, currencyCode, currencyDisplay),
      )
    : null;

  return (
    <div className={cn("flex flex-col gap-1", className)}>
      <div className="flex items-baseline gap-2">
        {isFree ? (
          <span className="text-3xl font-bold tracking-tight text-foreground">
            {labels.freeLabel}
          </span>
        ) : (
          <>
            <span className="text-3xl font-bold tracking-tight text-foreground">
              {formattedActive}
            </span>
            {showStrikethrough ? (
              <s
                className="text-sm text-muted-foreground"
                aria-label={`Was ${formattedMonthly} per month`}
              >
                {formattedMonthly}
              </s>
            ) : null}
          </>
        )}
      </div>
      {!isFree ? (
        <span className="text-xs text-muted-foreground">{periodCopy}</span>
      ) : null}
      {yearlyHintText ? (
        <span className="text-xs text-muted-foreground/80">
          {yearlyHintText}
        </span>
      ) : null}
    </div>
  );
}

import { useId } from "react";
import { cn } from "@/lib/utils";
import { PriceDisplay } from "./price-display";
import { TierCta } from "./tier-cta";
import { TierFeatureRow } from "./tier-feature-row";
import type {
  BillingPeriod,
  PricingTier,
  ResolvedLabels,
  ResolvedTone,
} from "../types";

interface TierCardProps {
  tier: PricingTier;
  billing: BillingPeriod;
  labels: ResolvedLabels;
  toneClasses: ResolvedTone;
  onTierCtaClick: (tierName: string) => void;
  className?: string;
  highlightedRingClassName?: string;
}

export function TierCard({
  tier,
  billing,
  labels,
  toneClasses,
  onTierCtaClick,
  className,
  highlightedRingClassName,
}: TierCardProps) {
  const titleId = useId();
  const isHighlighted = !!tier.highlighted;
  const badgeText = tier.badge ?? labels.popularBadge;

  return (
    <article
      role="region"
      aria-labelledby={titleId}
      className={cn(
        "relative flex flex-col gap-6 rounded-2xl border bg-card p-6 text-card-foreground",
        isHighlighted
          ? cn(
              "ring-2",
              toneClasses.highlightBorder,
              toneClasses.highlightRing,
              highlightedRingClassName,
            )
          : toneClasses.cardBorder,
        className,
      )}
    >
      {isHighlighted ? (
        <span
          className={cn(
            "absolute -top-3 start-6 inline-flex items-center rounded-full px-3 py-1 text-xs font-semibold uppercase tracking-wide",
            toneClasses.badgeBg,
            toneClasses.badgeText,
          )}
          aria-label={badgeText}
        >
          {badgeText}
        </span>
      ) : null}

      <header className="flex flex-col gap-1.5">
        <h3 id={titleId} className="text-lg font-semibold text-foreground">
          {tier.name}
        </h3>
        {tier.description ? (
          <p className="text-sm text-muted-foreground">{tier.description}</p>
        ) : null}
      </header>

      <PriceDisplay tier={tier} billing={billing} labels={labels} />

      <TierCta
        cta={tier.cta}
        tierName={tier.name}
        onTierCtaClick={onTierCtaClick}
      />

      <ul role="list" className="flex flex-col gap-2">
        {tier.features.map((feature, index) => (
          <TierFeatureRow
            key={`${feature.label}-${index}`}
            feature={feature}
            labels={labels}
          />
        ))}
      </ul>
    </article>
  );
}

import { isValidElement } from "react";
import type { MouseEvent, ReactNode } from "react";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";
import type { CtaSpec, CtaVariant } from "../types";

interface TierCtaProps {
  cta: ReactNode | CtaSpec;
  tierName: string;
  onTierCtaClick: (tierName: string) => void;
  className?: string;
}

function isCtaSpec(cta: ReactNode | CtaSpec): cta is CtaSpec {
  if (cta === null || typeof cta !== "object") return false;
  if (isValidElement(cta)) return false;
  const candidate = cta as Partial<CtaSpec>;
  if (typeof candidate.label !== "string") return false;
  return candidate.href !== undefined || candidate.onClick !== undefined;
}

function buttonVariantFor(variant: CtaVariant | undefined) {
  return variant === "outline" ? "outline" : "default";
}

export function TierCta({
  cta,
  tierName,
  onTierCtaClick,
  className,
}: TierCtaProps) {
  if (!isCtaSpec(cta)) {
    return <>{cta}</>;
  }

  const { label, href, onClick, variant, ariaLabel } = cta;
  const buttonVariant = buttonVariantFor(variant);

  const handleClick = (event: MouseEvent<HTMLElement>) => {
    onTierCtaClick(tierName);
    onClick?.();
    if (!href) event.preventDefault();
  };

  if (href) {
    return (
      <Button
        asChild
        variant={buttonVariant}
        className={cn("w-full", className)}
      >
        <a href={href} onClick={handleClick} aria-label={ariaLabel}>
          {label}
        </a>
      </Button>
    );
  }

  if (onClick) {
    return (
      <Button
        type="button"
        variant={buttonVariant}
        className={cn("w-full", className)}
        onClick={handleClick}
        aria-label={ariaLabel}
      >
        {label}
      </Button>
    );
  }

  if (process.env.NODE_ENV !== "production") {
    console.warn(
      `[pricing-table-01] tier "${tierName}" CTA spec has neither href nor onClick — rendering disabled button.`,
    );
  }

  return (
    <Button
      type="button"
      variant={buttonVariant}
      className={cn("w-full", className)}
      disabled
      aria-label={ariaLabel}
    >
      {label}
    </Button>
  );
}

